+            const var_type = self.var_types.get(name.id);
+            if (var_type) |vtype| {
+                if (std.mem.eql(u8, vtype, "string")) {
+                    try buf.writer(self.allocator).print("std.debug.print(\"{{s}}\\n\", .{{runtime.PyString.getValue({s})}})", .{arg_result.code});
+                } else {
